load(GROCERDIR+'/macros/grocer/db/bdhenderic.dat');
bounds()
res1=li_mcleod('delts(lm1)',6)
// Example taken from function li_mcleod_d. Provides the Li Mcleod test for the variation of the logrithm of M1
// in the UK and 1 to 6 autocorrelations.
r=varma_d4();
res2=li_mcleod(r,10)
// Also taken from function li_mcleod_d. Provides the Li Mcleod test for the residuals of the arma estimation
// provided in demo varma_d4() and 1 to 10 autocorrelations.
